import React, { useState } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements }) => {
    const [movement, setMovement] = useState({
        produto: '',
        tipo_movimentacao: 'entrada',
        quantidade: '',
        motivo: ''
    });

    const handleChange = (e) => {
        setMovement({ ...movement, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        try {
            await axios.post('http://127.0.0.1:8000/api/movimentacoes/', movement);
            refreshMovements(); // Atualiza a lista de movimentações
            setMovement({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' }); // Limpa o formulário
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <input name="produto" placeholder="Produto ID" onChange={handleChange} required />
            <select name="tipo_movimentacao" onChange={handleChange} required>
                <option value="entrada">Entrada</option>
                <option value="saida">Saída</option>
            </select>
            <input type="number" name="quantidade" placeholder="Quantidade" onChange={handleChange} required />
            <input name="motivo" placeholder="Motivo" onChange={handleChange} />
            <button type="submit">Registrar Movimentação</button>
        </form>
    );
};

export default StockMovementForm;
